import Button from '@mui/material/Button';
import Divider from '@mui/material/Divider';
import Grid from '@mui/material/Grid';
import InputLabel from '@mui/material/InputLabel';
import OutlinedInput from '@mui/material/OutlinedInput';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';

import { Formik } from 'formik';
import * as Yup from 'yup';

import MainCard from 'components/MainCard';
import useToast from 'app/providers/useToast';
import { roleLabel } from 'features/auth/roles';
import extractApiErrorMessage from 'utils/apiError';

import { changePassword } from 'features/auth/authService';
import useAuth from 'features/auth/useAuth';

export default function ProfilePage() {
  const { user } = useAuth();
  const { showToast } = useToast();

  if (!user) return null;

  return (
    <Grid container spacing={3}>
      <Grid size={{ xs: 12, md: 8 }}>
        <MainCard title="Mi perfil">
          <Grid container spacing={2}>
            <Grid size={{ xs: 12, md: 6 }}>
              <InputLabel>Nombre</InputLabel>
              <OutlinedInput value={user.first_name || '-'} fullWidth readOnly />
            </Grid>
            <Grid size={{ xs: 12, md: 6 }}>
              <InputLabel>Apellido</InputLabel>
              <OutlinedInput value={user.last_name || '-'} fullWidth readOnly />
            </Grid>
            <Grid size={{ xs: 12, md: 6 }}>
              <InputLabel>Correo</InputLabel>
              <OutlinedInput value={user.email || '-'} fullWidth readOnly />
            </Grid>
            <Grid size={{ xs: 12, md: 6 }}>
              <InputLabel>Rol</InputLabel>
              <OutlinedInput value={roleLabel(user.role)} fullWidth readOnly />
            </Grid>
          </Grid>
        </MainCard>
      </Grid>
      <Grid size={{ xs: 12, md: 4 }}>
        <MainCard title="Cambiar contraseña">
          <Formik
            initialValues={{ old_password: '', new_password: '' }}
            validationSchema={Yup.object({
              old_password: Yup.string().required('Contraseña actual requerida'),
              new_password: Yup.string().min(8, 'Mínimo 8 caracteres').required('Nueva contraseña requerida')
            })}
            onSubmit={async (values, { setSubmitting, resetForm }) => {
              try {
                await changePassword(values);
                showToast('Contraseña actualizada.', 'success');
                resetForm();
              } catch (err) {
                showToast(extractApiErrorMessage(err, 'No fue posible cambiar la contraseña.'), 'error');
              } finally {
                setSubmitting(false);
              }
            }}
          >
            {({ values, handleChange, handleSubmit, isSubmitting }) => (
              <form onSubmit={handleSubmit}>
                <Stack sx={{ gap: 1.5 }}>
                  <InputLabel htmlFor="old_password">Contraseña actual</InputLabel>
                  <OutlinedInput
                    id="old_password"
                    name="old_password"
                    type="password"
                    value={values.old_password}
                    onChange={handleChange}
                    fullWidth
                  />
                  <InputLabel htmlFor="new_password">Nueva contraseña</InputLabel>
                  <OutlinedInput
                    id="new_password"
                    name="new_password"
                    type="password"
                    value={values.new_password}
                    onChange={handleChange}
                    fullWidth
                  />
                  <Divider />
                  <Button type="submit" variant="contained" disabled={isSubmitting}>
                    Actualizar contraseña
                  </Button>
                </Stack>
              </form>
            )}
          </Formik>
        </MainCard>
      </Grid>
      <Grid size={12}>
        <MainCard title="Información de sesión">
          <Typography variant="body2">Usuario: {user.email}</Typography>
          <Typography variant="body2">Rol: {roleLabel(user.role)}</Typography>
          <Typography variant="body2">Estado: {user.is_active ? 'Activo' : 'Inactivo'}</Typography>
        </MainCard>
      </Grid>
    </Grid>
  );
}
